#!/usr/bin/env node
//
// bench-partition-strategies — the ADR-0045 B1 measurement protocol:
// `community` vs `hybrid` flat-large partitioning, compared on the metrics
// the B2 adopt-or-discard gate reads (boundary-call count, shard-size
// balance, cold wall-time, warm fragment-cache behavior).
//
// Drives the REAL CLI end-to-end (no engine-internal re-implementation —
// same posture as scripts/graph-catalog-diff.mjs): the corpus is a seeded
// flat-large fixture (generated by the COMPILED engine module
// packages/graph/engine/dist/.../_flat-large-fixture.js), the strategy is
// toggled ONLY by rewriting the corpus's opensip-tools.config.yml, and every
// number comes from `graph --profile` JSON artifacts (the ADR-0045 profile
// fields: boundaryCallSites / shardCount / shardSizes / shardsBuilt /
// shardsCached + the `partition` stage timing).
//
// Protocol per strategy (spec "Measurement harness (B1)"):
//   C  (cold):  delete <corpus>/opensip-tools/.runtime/, then
//               `graph --no-cache --profile … --concurrency <c>` × runs
//               (median reported).
//   prime:      one plain `graph` run (cache-writing).
//   W1 (warm):  `graph --profile …` on the unchanged tree — expect
//               cacheHit && shardsCached === shardCount (the integration-
//               level determinism proof: a fragment-cache hit requires
//               shard id + cacheKey + files-fingerprint to all match).
//   W2a:        append a comment to ONE file (no import change), run,
//               record shardsBuilt, revert (+ re-prime so W2b measures
//               only its own delta).
//   W2b:        add one import+call to that file, run, record shardsBuilt
//               (community's headline edit-stability metric), revert.
//
// Balance statistics (max/median ratio, coefficient of variation) are
// computed HERE from the profile's shardSizes — never in the engine (spec).
//
// Corpora: the default corpus is the seeded fixture. Passing `--corpus` a
// directory that EXISTS but is not the fixture (no `src/d0/f0000.ts` marker)
// switches to REAL-CORPUS mode (ADR-0045 B1 second corpus — e.g. a /tmp
// clone of a real flat-large repo): the generator is skipped, source files
// are walked recursively (same skip-dir set as `detectMonorepoLayout`), and
// the W2 edit/probe targets are picked deterministically from the sorted
// production file list (median file edited; probe = first file outside its
// two-segment directory prefix; W2b uses a namespace import so no export
// name needs to be known). The corpus's `opensip-tools.config.yml` is
// OVERWRITTEN per strategy — only ever point this at a disposable clone.
//
// Usage:
//   node scripts/bench-partition-strategies.mjs
//     [--corpus <dir>]        default: <tmpdir>/opensip-flat-large-fixture
//     [--files <n>]           fixture size, default 3000 (fixture mode only)
//     [--fresh]               rm + regenerate the fixture (fixture mode only)
//     [--strategies hybrid,community]
//     [--runs 3]              cold-run repetitions (median reported)
//     [--concurrency 4]       fixed for equal conditions
//     [--demote <rules>]      comma list of graph rules to demote to warning
//                             in the corpus config (default
//                             graph:high-blast-untested). Applied IDENTICALLY
//                             to both strategies; the rules still run — only
//                             the severity classification changes. Needed
//                             whenever a corpus shape trips an error-level
//                             rule (graph inherits failOnErrors: 1); never
//                             teach the bench to tolerate non-zero exits.
//     [--equivalence]         also run the fixture-level equivalence gate per
//                             strategy: graph-equivalence-check against a
//                             ZERO-floor budget written into the corpus
//                             (.config/graph-equivalence-budget.json). A
//                             non-zero exit = divergence = mechanically a bug
//                             in the prototype — the bench fails hard; never
//                             budget around it. Hybrid runs too (the control
//                             proving the harness itself is sound).
//     [--quick]               files=2600, runs=1 (sanity mode)
//
// Run `pnpm build` first — the script REQUIRES a fresh build and refuses to
// start without dist; remember that a STALE dist runs old behavior silently.

import { spawnSync } from 'node:child_process';
import { existsSync, mkdirSync, readdirSync, readFileSync, rmSync, writeFileSync } from 'node:fs';
import { tmpdir } from 'node:os';
import { basename, dirname, join, posix, resolve } from 'node:path';
import { fileURLToPath, pathToFileURL } from 'node:url';
import { parseArgs } from 'node:util';

const KNOWN_STRATEGIES = new Set(['directory-depth', 'file-count-chunks', 'hybrid', 'community']);
/** Equal-heap conditions for every child run (also what the exact oracle needs). */
const CHILD_NODE_OPTIONS = '--max-old-space-size=12288';

const repoRoot = resolve(dirname(fileURLToPath(import.meta.url)), '..');
const cli = join(repoRoot, 'packages', 'cli', 'dist', 'index.js');
const generatorDist = join(
  repoRoot,
  'packages',
  'graph',
  'engine',
  'dist',
  'cli',
  'orchestrate',
  '__tests__',
  '_flat-large-fixture.js',
);

const { values: args } = parseArgs({
  options: {
    corpus: { type: 'string' },
    files: { type: 'string' },
    fresh: { type: 'boolean', default: false },
    strategies: { type: 'string', default: 'hybrid,community' },
    runs: { type: 'string' },
    concurrency: { type: 'string', default: '4' },
    demote: { type: 'string', default: 'graph:high-blast-untested' },
    equivalence: { type: 'boolean', default: false },
    quick: { type: 'boolean', default: false },
  },
});

const quick = args.quick === true;
const defaultFileCount = quick ? 2600 : 3000;
const defaultRuns = quick ? 1 : 3;
const fileCount = args.files === undefined ? defaultFileCount : Number.parseInt(args.files, 10);
const runs = args.runs === undefined ? defaultRuns : Number.parseInt(args.runs, 10);
const concurrency = Number.parseInt(args.concurrency, 10);
const corpusDir = args.corpus ?? join(tmpdir(), 'opensip-flat-large-fixture');
const strategies = args.strategies
  .split(',')
  .map((s) => s.trim())
  .filter((s) => s.length > 0);

for (const strategy of strategies) {
  if (!KNOWN_STRATEGIES.has(strategy)) {
    console.error(`Unknown strategy '${strategy}' (known: ${[...KNOWN_STRATEGIES].join(', ')}).`);
    process.exit(1);
  }
}
if (!Number.isFinite(fileCount) || !Number.isFinite(runs) || !Number.isFinite(concurrency)) {
  console.error('--files, --runs and --concurrency must be integers.');
  process.exit(1);
}
if (!existsSync(cli) || !existsSync(generatorDist)) {
  console.error(
    `CLI or fixture generator not built (need ${cli} and ${generatorDist}).\n` +
      'Run `pnpm build` first — and remember a STALE dist runs old behavior silently:\n' +
      'always rebuild before benching.',
  );
  process.exit(1);
}
console.error(
  'bench-partition-strategies: driving packages/cli/dist — make sure `pnpm build` is FRESH ' +
    '(a stale dist runs old behavior silently).',
);

// ── corpus: generated fixture, or a real flat repo ────────────────

// A real corpus is an EXISTING directory without the fixture marker file —
// e.g. a /tmp clone of a real flat-large repo (ADR-0045 B1 second corpus).
const fixtureMarker = join(corpusDir, 'src', 'd0', 'f0000.ts');
const isRealCorpus = existsSync(corpusDir) && !existsSync(fixtureMarker);

if (isRealCorpus && args.fresh) {
  console.error('--fresh is fixture-only (it would DELETE the real corpus).');
  process.exit(1);
}
if (isRealCorpus && args.files !== undefined) {
  console.error('--files is fixture-only (a real corpus has its own file set).');
  process.exit(1);
}

let fixture; // fixture mode only (clusterCount drives W2 target math)
let corpusLabel;
if (isRealCorpus) {
  const sha = spawnSync('git', ['-C', corpusDir, 'rev-parse', '--short', 'HEAD'], {
    encoding: 'utf8',
  }).stdout?.trim();
  corpusLabel = `${basename(corpusDir)} (real corpus${sha ? ` @ ${sha}` : ''})`;
  console.error(`corpus: real repo at ${corpusDir} — ${corpusLabel}`);
} else {
  if (args.fresh) {
    rmSync(corpusDir, { recursive: true, force: true });
  }
  const { generateFlatLargeFixture } = await import(pathToFileURL(generatorDist).href);
  fixture = generateFlatLargeFixture(corpusDir, { fileCount });
  if (fixture.skipped) {
    console.error(
      `corpus: reusing existing fixture at ${corpusDir} (warm-safe; --files is ignored — ` +
        'pass --fresh to regenerate).',
    );
  } else {
    console.error(
      `corpus: generated ${String(fixture.fileCount)} files / ` +
        `${String(fixture.clusterCount)} clusters at ${corpusDir}`,
    );
  }
  corpusLabel = `flat-large-fixture (${String(fixture.fileCount)} files, ${String(fixture.clusterCount)} clusters)`;
}

const benchDir = join(corpusDir, '.bench');
mkdirSync(benchDir, { recursive: true });

// ── child-process + profile helpers ───────────────────────────────

/**
 * Run `node <cli> graph …` inside the corpus; throw on a non-zero exit.
 * `--no-cloud` keeps the cloud-sync sink a no-op so no network attempt ever
 * sits inside a timed run (equal, machine-local conditions).
 */
function runGraph(graphArgs) {
  const res = spawnSync(process.execPath, [cli, ...graphArgs, '--no-cloud'], {
    cwd: corpusDir,
    env: { ...process.env, NODE_OPTIONS: CHILD_NODE_OPTIONS },
    stdio: ['ignore', 'ignore', 'inherit'],
  });
  if (res.status !== 0) {
    throw new Error(`\`graph ${graphArgs.join(' ')}\` exited ${String(res.status)}`);
  }
}

/** Read a --profile artifact: { durationMs, summary, partition stage }. */
function readProfile(path) {
  const doc = JSON.parse(readFileSync(path, 'utf8'));
  const run = doc.runs[0] ?? {};
  const stages = run.stages ?? [];
  return {
    durationMs: doc.durationMs ?? run.durationMs ?? 0,
    summary: run.summary ?? {},
    partitionStage: stages.find((s) => s.name === 'partition'),
  };
}

function median(values) {
  const sorted = [...values].sort((a, b) => a - b);
  const mid = Math.floor(sorted.length / 2);
  return sorted.length % 2 === 1 ? sorted[mid] : (sorted[mid - 1] + sorted[mid]) / 2;
}

/** Balance statistics over a (desc-sorted) shardSizes array. */
function balanceStats(sizes) {
  if (!Array.isArray(sizes) || sizes.length === 0) {
    return { maxOverMedian: Number.NaN, cv: Number.NaN };
  }
  const max = Math.max(...sizes);
  const med = median(sizes);
  const mean = sizes.reduce((a, b) => a + b, 0) / sizes.length;
  const variance = sizes.reduce((a, b) => a + (b - mean) ** 2, 0) / sizes.length;
  return {
    maxOverMedian: med === 0 ? Number.NaN : max / med,
    cv: mean === 0 ? Number.NaN : Math.sqrt(variance) / mean,
  };
}

// ── W2 edit-target selection ──────────────────────────────────────

/** Sorted repo-relative POSIX paths of every generated source file (fixture layout). */
function listFixtureSourceFiles() {
  const out = [];
  const srcDir = join(corpusDir, 'src');
  for (const dir of readdirSync(srcDir)) {
    for (const file of readdirSync(join(srcDir, dir))) {
      if (file.endsWith('.ts')) out.push(`src/${dir}/${file}`);
    }
  }
  out.sort();
  return out;
}

/**
 * Sorted repo-relative POSIX paths of every `.ts`/`.tsx` (non-`.d.ts`)
 * file in a REAL corpus — recursive walk with the same skip-dir set
 * `detectMonorepoLayout` uses, so the W2 targets are files the engine
 * actually discovers.
 */
function listRealSourceFiles() {
  const SKIPPED = new Set(['node_modules', 'dist', 'build', '.git', '.turbo', 'coverage', '.next']);
  const out = [];
  const visit = (relDir) => {
    const abs = relDir === '' ? corpusDir : join(corpusDir, relDir);
    let entries;
    try {
      entries = readdirSync(abs, { withFileTypes: true });
    } catch {
      return;
    }
    for (const entry of entries) {
      const rel = relDir === '' ? entry.name : `${relDir}/${entry.name}`;
      if (entry.isDirectory()) {
        if (!SKIPPED.has(entry.name)) visit(rel);
      } else if (/\.tsx?$/.test(entry.name) && !entry.name.endsWith('.d.ts')) {
        out.push(rel);
      }
    }
  };
  visit('');
  out.sort();
  return out;
}

const indexOfRel = (rel) => Number.parseInt(/f(\d+)\.ts$/.exec(rel)?.[1] ?? 'NaN', 10);

/**
 * Deterministic FIXTURE W2 edit target: the HIGHEST-indexed file that (a)
 * carries no cross-cluster import (index % 10 !== 0) and (b) is not in
 * cluster 0 — so the W2b probe import of f0000 (cluster 0) can never
 * duplicate an existing import of the edited file.
 */
function pickEditTarget(files, clusterCount) {
  for (let i = files.length - 1; i >= 0; i--) {
    const rel = files[i];
    const index = indexOfRel(rel);
    if (Number.isFinite(index) && index % 10 !== 0 && index % clusterCount !== 0) return rel;
  }
  throw new Error('No suitable W2 edit target found in the corpus.');
}

/**
 * Deterministic REAL-corpus W2 targets: edit the MEDIAN production file
 * (sorted order; tests excluded so the edit is representative of production
 * cache behavior), probe-import the first production file whose first two
 * path segments differ from the edit target's (far away in directory terms,
 * so the new import edge plausibly crosses a community boundary). The W2b
 * probe is a NAMESPACE import + use — valid against any module without
 * knowing its export names; it changes the import graph (what community
 * partitioning consumes) even though it is not a call.
 */
function pickRealEditTargets(files) {
  const production = files.filter(
    (rel) => !rel.includes('__tests__/') && !/\.(test|spec)\.tsx?$/.test(rel),
  );
  if (production.length < 2) throw new Error('Real corpus has too few production source files.');
  const edit = production[Math.floor(production.length / 2)];
  const editPrefix = edit.split('/').slice(0, 2).join('/');
  const probe = production.find((rel) => rel.split('/').slice(0, 2).join('/') !== editPrefix);
  if (probe === undefined) throw new Error('No W2b probe target outside the edit directory.');
  return { edit, probe };
}

let editRel;
let probeTargetRel;
let probeExtension; // fixture imports use explicit .js (NodeNext); real corpora extensionless
if (isRealCorpus) {
  const picked = pickRealEditTargets(listRealSourceFiles());
  editRel = picked.edit;
  probeTargetRel = picked.probe;
  probeExtension = '';
} else {
  const sourceFiles = listFixtureSourceFiles();
  editRel = pickEditTarget(sourceFiles, fixture.clusterCount);
  probeTargetRel = sourceFiles.find((rel) => rel.endsWith('/f0000.ts'));
  if (probeTargetRel === undefined) throw new Error('Corpus has no f0000.ts probe target.');
  probeExtension = '.js';
}
const editAbs = join(corpusDir, editRel);
const relSpec = posix
  .relative(posix.dirname(editRel), probeTargetRel)
  .replace(/\.tsx?$/, probeExtension);
const probeImportSpec = relSpec.startsWith('.') ? relSpec : `./${relSpec}`;
console.error(`W2 targets: edit=${editRel} probe-import=${probeTargetRel}`);

const W2A_SUFFIX = '\n// w2a body-edit probe (no import change)\n';
const W2B_SUFFIX = isRealCorpus
  ? `\nimport * as __w2bProbe from '${probeImportSpec}';\n` +
    'export function w2bProbe(): unknown {\n  return __w2bProbe;\n}\n'
  : `\nimport { f0000 } from '${probeImportSpec}';\n` +
    'export function w2bProbe(): number {\n  return f0000();\n}\n';

// ── protocol ──────────────────────────────────────────────────────

/**
 * Strategy toggling happens ONLY here (spec protocol).
 *
 * The `--demote` rules (default `graph:high-blast-untested`: the synthetic
 * corpus has NO tests by design, so its hub functions all trip the rule at
 * error level, and ADR-0035's host verdict gate (failOnErrors: 1) would fail
 * every plain run) are demoted to warning. The demotion applies identically
 * to both strategies and the rules still RUN (same rule work, same
 * wall-time) — only the severity classification changes. If a corpus shape
 * trips another error-level rule, demote that rule explicitly via `--demote`;
 * never teach the bench to tolerate non-zero graph exits (that would mask
 * real runtime failures).
 */
const demotedRules = args.demote
  .split(',')
  .map((s) => s.trim())
  .filter((s) => s.length > 0);

function writeCorpusConfig(strategy) {
  const overrides =
    demotedRules.length === 0
      ? ''
      : `  severityOverrides:\n${demotedRules.map((r) => `    '${r}': warning\n`).join('')}`;
  writeFileSync(
    join(corpusDir, 'opensip-tools.config.yml'),
    `schemaVersion: 1\n` + `graph:\n` + `  partitionStrategy: ${strategy}\n` + overrides,
    'utf8',
  );
}

function profileArgs(name) {
  return ['--profile', join(benchDir, name), '--concurrency', String(concurrency)];
}

/**
 * Fixture-level equivalence gate (spec "Differential guardrail" §2): run the
 * REAL `graph-equivalence-check` command against the corpus with the current
 * strategy configured (the command shards via resolveShardsForCwd, which
 * honors the corpus config) and ZERO directional floors. NOT a budget ratchet:
 * any divergence is mechanically a prototype bug — fail hard, never budget
 * around it (the REPO budget .config/graph-equivalence-budget.json is out of
 * scope for this track). NOT a CI step during the prototype (fixture
 * generation + double build is too heavy per PR); it IS the pre-commit bar
 * for Phase 2+ behavioral commits.
 */
function runEquivalence(strategy) {
  console.error(`[${strategy}] equivalence gate (graph-equivalence-check, zero floors)`);
  mkdirSync(join(corpusDir, '.config'), { recursive: true });
  const budget = {
    phantomDivergences: 0,
    declineDivergences: 0,
    conflictDivergences: 0,
    sccDivergences: 0,
  };
  writeFileSync(
    join(corpusDir, '.config', 'graph-equivalence-budget.json'),
    `${JSON.stringify(budget, null, 2)}\n`,
    'utf8',
  );
  const res = spawnSync(process.execPath, [cli, 'graph-equivalence-check'], {
    cwd: corpusDir,
    env: { ...process.env, NODE_OPTIONS: CHILD_NODE_OPTIONS },
    stdio: ['ignore', 'pipe', 'inherit'],
    encoding: 'utf8',
  });
  // Echo the verdict lines to the progress channel (stderr) so stdout stays
  // the pasteable Markdown table.
  if (typeof res.stdout === 'string' && res.stdout.length > 0) process.stderr.write(res.stdout);
  return res.status === 0;
}

/** One edited-tree warm run: apply `suffix` to the edit target, run, revert, re-prime. */
function runEditScenario(strategy, label, suffix) {
  const original = readFileSync(editAbs, 'utf8');
  writeFileSync(editAbs, `${original}${suffix}`, 'utf8');
  try {
    const name = `${label}-${strategy}.json`;
    runGraph(['graph', ...profileArgs(name)]);
    return readProfile(join(benchDir, name));
  } finally {
    writeFileSync(editAbs, original, 'utf8'); // revert (rewrites original content)
    // Re-prime: the revert itself changed the file's mtime (the fingerprint is
    // mtime+size), so prime once more — the NEXT scenario then measures only
    // its own edit delta, not this revert's.
    runGraph(['graph', '--concurrency', String(concurrency)]);
  }
}

function benchStrategy(strategy) {
  console.error(`\n=== strategy: ${strategy} ===`);
  writeCorpusConfig(strategy);

  // C (cold): empty runtime state, then --no-cache × runs.
  rmSync(join(corpusDir, 'opensip-tools', '.runtime'), { recursive: true, force: true });
  const colds = [];
  for (let i = 0; i < runs; i++) {
    console.error(`[${strategy}] cold run ${String(i + 1)}/${String(runs)}`);
    const name = `cold-${strategy}-${String(i)}.json`;
    runGraph(['graph', '--no-cache', ...profileArgs(name)]);
    colds.push(readProfile(join(benchDir, name)));
  }
  const coldMedianMs = median(colds.map((c) => c.durationMs));
  const cold = colds[0]; // shard shape is deterministic across cold runs

  // Prime the fragment cache, then W1 (unchanged warm).
  console.error(`[${strategy}] prime + W1 (unchanged warm)`);
  runGraph(['graph', '--concurrency', String(concurrency)]);
  const w1Name = `warm-${strategy}.json`;
  runGraph(['graph', ...profileArgs(w1Name)]);
  const w1 = readProfile(join(benchDir, w1Name));
  const w1FullyCached =
    w1.summary.cacheHit === true && w1.summary.shardsCached === w1.summary.shardCount;

  // W2a (body edit) / W2b (import edit).
  console.error(`[${strategy}] W2a (body edit) on ${editRel}`);
  const w2a = runEditScenario(strategy, 'w2a', W2A_SUFFIX);
  console.error(`[${strategy}] W2b (import edit) on ${editRel}`);
  const w2b = runEditScenario(strategy, 'w2b', W2B_SUFFIX);

  // Equivalence gate last — its catalogs build cold/no-cache/in-memory, so it
  // never disturbs the fragment cache the W phases primed.
  const equivalencePassed = args.equivalence ? runEquivalence(strategy) : undefined;

  const balance = balanceStats(cold.summary.shardSizes);
  return {
    strategy,
    boundaryCallSites: cold.summary.boundaryCallSites,
    shardCount: cold.summary.shardCount,
    maxOverMedian: balance.maxOverMedian,
    cv: balance.cv,
    coldMedianMs,
    partitionMs: cold.partitionStage?.durationMs,
    partitionDetail: cold.partitionStage?.detail,
    w1FullyCached,
    w1DurationMs: w1.durationMs,
    w2aShardsBuilt: w2a.summary.shardsBuilt,
    w2bShardsBuilt: w2b.summary.shardsBuilt,
    equivalencePassed,
  };
}

// ── run + report ──────────────────────────────────────────────────

const rows = strategies.map((strategy) => benchStrategy(strategy));

const fmt = (v, digits = 0) =>
  typeof v === 'number' && Number.isFinite(v) ? v.toFixed(digits) : 'n/a';

console.log(`\n## Partition-strategy bench — ${corpusLabel}\n`);
console.log(
  `Conditions: runs=${String(runs)} (median), concurrency=${String(concurrency)}, ` +
    `NODE_OPTIONS=${CHILD_NODE_OPTIONS}, corpus=${corpusDir}\n`,
);
const equivalenceCell = (r) => {
  if (r.equivalencePassed === undefined) return 'not run';
  return r.equivalencePassed ? 'PASS' : 'FAIL';
};
console.log(
  '| strategy | shards | boundary calls | max/median | CV | cold median ms | partition ms | W1 fully cached | W1 warm ms | W2a shardsBuilt | W2b shardsBuilt | equivalence |',
);
console.log('|---|---|---|---|---|---|---|---|---|---|---|---|');
for (const r of rows) {
  console.log(
    `| ${r.strategy} | ${fmt(r.shardCount)} | ${fmt(r.boundaryCallSites)} | ` +
      `${fmt(r.maxOverMedian, 2)} | ${fmt(r.cv, 2)} | ${fmt(r.coldMedianMs)} | ` +
      `${fmt(r.partitionMs)} | ${r.w1FullyCached ? 'yes' : 'NO'} | ${fmt(r.w1DurationMs)} | ` +
      `${fmt(r.w2aShardsBuilt)} | ${fmt(r.w2bShardsBuilt)} | ${equivalenceCell(r)} |`,
  );
}
console.log('');
for (const r of rows) {
  if (r.partitionDetail !== undefined) {
    console.log(`- ${r.strategy} partition stage: ${r.partitionDetail}`);
  }
}
const notCached = rows.filter((r) => !r.w1FullyCached);
if (notCached.length > 0) {
  console.error(
    `\nWARNING: W1 was NOT fully cached for: ${notCached.map((r) => r.strategy).join(', ')} — ` +
      'an unchanged-tree warm run must be a 100% fragment-cache hit (determinism proof). ' +
      'Treat as a Phase 0-3 bug.',
  );
  process.exitCode = 1;
}
const diverged = rows.filter((r) => r.equivalencePassed === false);
if (diverged.length > 0) {
  console.error(
    `\nFAIL: equivalence divergence under: ${diverged.map((r) => r.strategy).join(', ')} — ` +
      'mechanically a bug in the prototype (ADR-0033: partition layout must not be ' +
      'observable in the merged catalog). Fix it; never budget around it.',
  );
  process.exitCode = 1;
}
